SELECT * FROM store_sales, store_returns, date_dim, store, item, promotion, catalog_sales, catalog_returns, catalog_page, web_sales, web_returns, web_site WHERE ss_sold_date_sk = d_date_sk AND ss_store_sk = s_store_sk AND ss_item_sk = i_item_sk AND i_current_price > 50 AND ss_promo_sk = p_promo_sk AND p_channel_tv = "N" AND cs_sold_date_sk = d_date_sk AND cs_catalog_page_sk = cp_catalog_page_sk AND cs_item_sk = i_item_sk AND cs_promo_sk = p_promo_sk AND ws_sold_date_sk = d_date_sk AND ws_web_site_sk = web_site_sk AND ws_item_sk = i_item_sk AND ws_promo_sk = p_promo_sk AND (ss_item_sk = sr_item_sk AND ss_ticket_number = sr_ticket_number) AND (cs_item_sk = cr_item_sk AND cs_order_number = cr_order_number) AND (ws_item_sk = wr_item_sk AND ws_order_number = wr_order_number);
